import{_ as r,C as o,o as s,c as l,E as a,w as t,a as n,a0 as d}from"./chunks/framework.CkNTPv-z.js";const w=JSON.parse('{"title":"Estonia Legal Rights","description":"Legal rights for transgender people in Estonia","frontmatter":{"layout":"doc","title":"Estonia Legal Rights","description":"Legal rights for transgender people in Estonia"},"headers":[],"relativePath":"europe/estonia/legal-rights.md","filePath":"europe/estonia/legal-rights.md","lastUpdated":null}'),c={name:"europe/estonia/legal-rights.md"};function g(h,e,u,m,p,f){const i=o("Badge");return s(),l("div",null,[a(i,{variant:"yellow"},{default:t(()=>[...e[0]||(e[0]=[n("Medicalized Recognition",-1)])]),_:1}),a(i,{variant:"green"},{default:t(()=>[...e[1]||(e[1]=[n("Anti-Discrimination Protections",-1)])]),_:1}),a(i,{variant:"yellow"},{default:t(()=>[...e[2]||(e[2]=[n("Reform Proposed (Not Passed)",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="legal-rights-in-estonia" tabindex="-1">Legal Rights in Estonia <a class="header-anchor" href="#legal-rights-in-estonia" aria-label="Permalink to &quot;Legal Rights in Estonia&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Estonia currently operates a <strong>medicalized model</strong> for legal gender recognition:</p><ul><li><strong>Requirements</strong>: Diagnosis of gender dysphoria + undergoing HRT or other medical treatment</li><li><strong>Age</strong>: 18+ can apply; 15-18 with parental consent</li><li><strong>Process</strong>: Application to the civil registry with supporting medical documentation</li><li><strong>Surgery</strong>: Not explicitly required in law, but medical evidence of treatment is needed</li></ul><h3 id="proposed-reform" tabindex="-1">Proposed Reform <a class="header-anchor" href="#proposed-reform" aria-label="Permalink to &quot;Proposed Reform&quot;">​</a></h3><p>A self-determination bill was proposed in 2022-2023 but has not yet passed. If enacted, it would:</p><ul><li>Allow legal gender change by simple administrative declaration</li><li>Remove medical requirements</li><li>Introduce legal recognition for non-binary genders</li><li>Reduce the minimum age to 16</li></ul><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name changes are processed through the <strong>civil registry</strong> (Rahvastikuregister)</li><li>No specific medical requirements for name changes alone</li><li>Can be done alongside gender marker change</li><li>Processed within 1-3 months</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Estonia prohibits discrimination based on sexual orientation and gender identity in:</p><ul><li><strong>Employment</strong> (Equal Treatment Act)</li><li><strong>Goods and services</strong> (including housing, education)</li><li><strong>Healthcare access</strong></li></ul><p>The <strong>Gender Equality Act</strong> and <strong>Equal Treatment Act</strong> form the legal basis, though enforcement can be inconsistent.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Gender identity is recognized as a protected characteristic in hate crime legislation. The Penal Code provides for enhanced penalties for crimes motivated by hatred based on sexual orientation or gender identity. Prosecution of transphobic hate crimes remains relatively rare.</p><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports and ID cards are recognized internationally</li><li>Estonia issues a digital ID card — updated documents work with e-services</li><li>Previous gender marker is not disclosed on updated documents</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.sm.ee/" target="_blank" rel="noreferrer">Estonian Ministry of Social Affairs</a></li><li><a href="https://trans.ee/" target="_blank" rel="noreferrer">Trans in Estonia</a></li><li><a href="https://humanrights.ee/" target="_blank" rel="noreferrer">Estonian Human Rights Centre</a></li></ul>',19))])}const q=r(c,[["render",g]]);export{w as __pageData,q as default};
